"use strict";(self.webpackChunkdst_api_webdocs=self.webpackChunkdst_api_webdocs||[]).push([[14317],{84860:e=>{e.exports=JSON.parse('{"tag":{"label":"perishable","permalink":"/dst-api-webdocs/docs/tags/perishable","allTagsPath":"/dst-api-webdocs/docs/tags","count":25,"items":[{"id":"game-scripts/prefabs/bathbomb","title":"Bathbomb","description":"A consumable item that provides fuel and can be burned, featuring perishable behavior and inventory compatibility.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/bathbomb"},{"id":"game-scripts/prefabs/bullkelp_root","title":"Bullkelp Root","description":"A deployable, perishable weapon that functions as a whip; when equipped, it overrides entity animations and can snap to deal damage while consuming spoilage.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/bullkelp_root"},{"id":"game-scripts/prefabs/butterflywings","title":"Butterflywings","description":"A consumable inventory item that heals health and hunger but perishes quickly; used as a food source or cat toy.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/butterflywings"},{"id":"game-scripts/prefabs/canary_poisoned","title":"Canary Poisoned","description":"Represents a poisoned canary entity that cannot be picked up while alive or dead, spoils over time, and drops spoiled food upon death.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/canary_poisoned"},{"id":"game-scripts/prefabs/crumbs","title":"Crumbs","description":"A small consumable item used as bait or pet food, which spoils over time and has minimal nutritional value.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/crumbs"},{"id":"game-scripts/prefabs/cutlichen","title":"Cutlichen","description":"A consumable food item that restores health and hunger but reduces sanity, and spoils over time.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/cutlichen"},{"id":"game-scripts/components/edible","title":"Edible","description":"Manages nutritional and thermal properties of food items, including health/hunger/sanity restoration, spoilage effects, and temperature impact on consumers.","permalink":"/dst-api-webdocs/docs/game-scripts/components/edible"},{"id":"game-scripts/prefabs/eel","title":"Eel","description":"Generates raw and cooked eel prefabs with configurable states, perishability, dryability, and cooking yields.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/eel"},{"id":"game-scripts/prefabs/forgetmelots","title":"Forgetmelots","description":"A consumable vegetarian item that provides minimal sanity restoration, spoils quickly, and can be dried; also serves as a cat toy and vase decoration.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/forgetmelots"},{"id":"game-scripts/prefabs/goatmilk","title":"Goatmilk","description":"A consumable food item that restores health, hunger, and sanity, but spoils quickly and can be fed to cats.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/goatmilk"},{"id":"game-scripts/components/gym","title":"Gym","description":"Manages training interactions with a trainee entity, including training timer management, perishability checks, music state transitions, and phase-based rest behavior.","permalink":"/dst-api-webdocs/docs/game-scripts/components/gym"},{"id":"game-scripts/prefabs/hambat","title":"Hambat","description":"A perishable melee weapon whose damage decreases as it spoils over time.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/hambat"},{"id":"game-scripts/prefabs/hareball","title":"Hareball","description":"A consumable, renewable cat toy that perishes over time and can be ignited or thrown.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/hareball"},{"id":"game-scripts/prefabs/hawaiianshirt","title":"Hawaiianshirt","description":"A wearable clothing item that provides summer insulation, spoils over time, and handles skinned item rendering on equip/unequip.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/hawaiianshirt"},{"id":"game-scripts/prefabs/honey","title":"Honey","description":"A consumable food item that restores health and hunger, with slow perish rate and stackability.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/honey"},{"id":"game-scripts/prefabs/meats","title":"Meats","description":"Factory function for creating various meat-based food prefabs with standardized components and behaviors.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/meats"},{"id":"game-scripts/prefabs/moonstorm_spark","title":"Moonstorm Spark","description":"A floating, ephemeral lightning-based entity that periodically emits electric shocks to nearby targets and can be recharged by moonsparkchargeable components; it ages over time and disappears when depleted.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/moonstorm_spark"},{"id":"game-scripts/prefabs/preparedfoods","title":"Preparedfoods","description":"A prefabricated generator function factory that creates fully configured prepared food entities with configurable nutrition, perishability, and spice effects.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/preparedfoods"},{"id":"game-scripts/prefabs/pumpkin_lantern","title":"Pumpkin Lantern","description":"Manages the lifecycle, lighting, and day/night transitions for the pumpkin lantern item, including fading animations, perishability, and loot drops.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/pumpkin_lantern"},{"id":"game-scripts/prefabs/royal_jelly","title":"Royal Jelly","description":"A consumable food item that restores health, hunger, and sanity; has a moderate perish time and can be stacked.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/royal_jelly"},{"id":"game-scripts/components/stewer","title":"Stewer","description":"Manages cooking and spoilage timers for stew pot entities, handling cooking progression, product generation, and spoilage logic.","permalink":"/dst-api-webdocs/docs/game-scripts/components/stewer"},{"id":"game-scripts/prefabs/tallbirdegg","title":"Tallbirdegg","description":"A hatchable egg prefab that requires specific environmental conditions to successfully hatch into a smallbird, spoil, or produce different loot based on temperature exposure.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/tallbirdegg"},{"id":"game-scripts/prefabs/trunk","title":"Trunk","description":"Creates the raw trunk item (summer, winter, cooked variants) for Koalephant, a meat-based food item with perishable and tradable properties.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/trunk"},{"id":"game-scripts/prefabs/wormlight","title":"Wormlight","description":"Manages the lifecycle and visual effects of a consumable light source that transfers to a player or creature upon eating, providing light while it lasts before extinguishing.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/wormlight"},{"id":"game-scripts/prefabs/yotr_food","title":"Yotr Food","description":"Defines four configurable food prefabs (carrot roll, moon cake, Moon Jelly, and dango) with custom nutritional and perishability values for Don\'t Starve Together.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/yotr_food"}],"unlisted":false}}')}}]);